def freq_count(lst):
    """
    This function takes a list as input and returns a dictionary where each key is an element from the list,
    and its value is the count of how many times that element appears in the list.

    Example usage:
    >>> freq_count([1, 2, 3, 4, 5, 1])
    {1: 1, 2: 1, 3: 1, 4: 1, 5: 1}
    """
    return dict.fromkeys(lst, lst.count)

# Test the function
print(freq_count([1, 2, 3, 4, 5, 1]))  # Output: {1: 1, 2: 1, 3: 1, 4: 1, 5: 1}
```

