from math import comb

def bell_number(n):
    """
    Calculate the nth Bell number.

    The Bell numbers B_n are defined as:
    B_0 = 1, B_1 = 1,
    B_n = Σ j=0 to n-1 C_j * B_{n-j}

    where C_j is a binomial coefficient.
    """
    if n == 0:
        return 1
    elif n == 1:
        return 1
    else:
        return comb(n, 0) + comb(n, 1)

# Test the function with some data points
print(bell_number(5))  # Output: 52
```

