def merge_dictionaries_three(dict1, dict2, dict3):
    """
    Merge three dictionaries into a single expression.

    Args:
        dict1 (dict): The first dictionary.
        dict2 (dict): The second dictionary.
        dict3 (dict): The third dictionary.

    Returns:
        dict: A new dictionary containing the merged keys and values from all input dictionaries.
    """
    return {**dict1, **dict2, **dict3}

# Test cases to verify the correctness of the function
def check_function():
    d1 = {'a': 1, 'b': 2}
    d2 = {'b': 3, 'c': 4}
    d3 = {'d': 5, 'e': 6}

    expected_output = {'a': 1, 'b': 3, 'c': 4, 'd': 5, 'e': 6}
    assert merge_dictionaries_three(d1, d2, d3) == expected_output, "Test case failed!"

    print("All test cases passed!")

check_function()
